        ac = []
    elif len(ac) < 1:
        errors.append("'acceptance_criteria' must have at least 1 item")

    counts = {"structural": 0, "unit": 0, "user-journey": 0, "edge-case": 0}

    for i, criterion in enumerate(ac):
